com.mirth.connect.plugins.javascriptstep.script:
var interactionId = globalMap.get('interactionId');
var logPrefix = "[CHANNEL: " + channelName + "] [INTERACTION ID: " + interactionId + "] ";

logger.info(logPrefix + "HTTP request validation started.");

var requestedPath = sourceMap.get('contextPath');
logger.info(logPrefix + "Request URL: " + requestedPath);

if (requestedPath == "/") {
	return;
}

// Initialize missing headers array
var missingHeaders = [];

// Helper to check and store missing header
function checkRequiredHeader(headerName, displayName, storeInMap, mapKey) {
    var value = $('headers').getHeader(headerName);
    logger.info(logPrefix + headerName + ": " + value);

    if (value == null || String(value).trim() === "") {
        missingHeaders.push("Missing required header " + displayName);
    } else if (storeInMap) {
        channelMap.put(mapKey || headerName, value);
        globalMap.put(mapKey || headerName, value);
    }
    return value;
}

///////////////////////////////////////////////////////////////////////////
// Access the required header values using getHeader method
// Mandatory: X-TechBD-Tenant-ID
checkRequiredHeader('X-TechBD-Tenant-ID', 'X-TechBD-Tenant-ID', true, 'tenantId');
channelMap.put('X-TechBD-Tenant-ID', tenantId);
// Retrieve the Content-Type header
var contentType = $('headers').getHeader('Content-Type');

// Check if the Content-Type is 'multipart/form-data' and contains a boundary
if (!contentType || !contentType.startsWith('multipart/form-data') /*|| !contentType.includes('boundary=')*/) {
    missingHeaders.push("Content-Type must be 'multipart/form-data' with boundary details");
}

// Get User-Agent header to set at HTTP Writer not to show 'Mirth connect' as Agent at the application side.
var userAgent = $('headers').getHeader('User-Agent');
channelMap.put('userAgent', userAgent);
globalMap.put('userAgent', userAgent);

var OrganizationName = $('headers').getHeader('X-TechBD-Organization-Name');
channelMap.put('OrganizationName', OrganizationName);

var severityLevel = String($('headers').getHeader('X-TechBD-Validation-Severity-Level') || "").trim();
channelMap.put('SeverityLevel', severityLevel || "error");

// Single consolidated log
logger.info(
    logPrefix +
    "TenantId: " + tenantId +
    ", Content-Type: " + contentType +
    ", User-Agent: " + userAgent +
    ", OrganizationName: " + OrganizationName +
    ", SeverityLevel: " + (severityLevel || "error")
);

channelMap.put('uri', sourceMap.get('uri'));
channelMap.put('contextPath', sourceMap.get('contextPath'));

/********************************************
    5️⃣ FETCH DEFAULT DATALAKE API URL (Plain text)
********************************************/
var datalakeApiUrl="";

var rawHeader = $('headers').getHeader('X-TechBD-DataLake-API-URL');
var incomingHeader = rawHeader == null ? "" : String(rawHeader).trim();

//if (incomingHeader.indexOf("=") !== -1) {
// 
//	logger.info("************************");
// 
//    setErrorResponse(
// 
//        400,
// 
//        "Invalid X-TechBD-DataLake-API-URL"
// 
//    );
// 
//    throw "SSRF validation failed";
// 
//}if (incomingHeader.indexOf("=") !== -1) {



    setErrorResponse(

        400,

        "Invalid X-TechBD-DataLake-API-URL1111111111111111111111111111111111111111"

    );

    throw "SSRF validation failed";

}

logger.info("incomingHeader=[" + incomingHeader + "]");
var allowedUrlsConfig = LookupHelper.get(

    "Config",

    "TECHBD_DEFAULT_DATALAKE_API_URL"

);
if (!allowedUrlsConfig || String(allowedUrlsConfig).trim() === "") {

    throw "TECHBD_DEFAULT_DATALAKE_API_URL is empty.";

}
allowedUrlsConfig = String(allowedUrlsConfig).trim();
// incomingHeader="";
if (incomingHeader !== "") {	 	

    var allowedUrls = allowedUrlsConfig.split(",");

    var isAllowed = false;
    for (var i = 0; i < allowedUrls.length; i++) {

        var allowedUrl = String(allowedUrls[i]).trim();
        logger.info(

            "Comparing incoming=[" +

            incomingHeader +

            "] with allowed=[" +

            allowedUrl +

            "]"

        );
        if (incomingHeader === allowedUrl) {

            isAllowed = true;

            break;

        }

    }
    if (!isAllowed) {

        logger.error(

            "Rejected DataLake API URL. Incoming: " +

            incomingHeader +

            ", Allowed URLs: " +

            allowedUrlsConfig

        );
        setErrorResponse(

            400,

            "Invalid X-TechBD-DataLake-API-URL. Only approved DataLake URL is allowed."

        );
        throw "SSRF validation failed";

    }
    datalakeApiUrl = incomingHeader;

} else {

    // Use first URL from whitelist as default

    datalakeApiUrl = String(

        allowedUrlsConfig.split(",")[0]

    ).trim();

}
channelMap.put("datalakeApiUrl", datalakeApiUrl);
/////////////////////////////////////////////////////
/********************************************
    5️⃣ FETCH DEFAULT DATALAKE API URL (Plain text)
    WITH HEADER OVERRIDE SUPPORT
********************************************/

    // First, check if the header override is provided
    var headerDataLakeApiUrl = $('headers').getHeader('X-TechBD-DataLake-API-URL');

    if (headerDataLakeApiUrl && String(headerDataLakeApiUrl).trim() !== "") {
        // Header provided - use it as override
        headerDataLakeApiUrl = headerDataLakeApiUrl.trim();

        channelMap.put("datalakeApiUrl", headerDataLakeApiUrl);
    } 



//** Get CIN, NPI and TIN from headers for CCDA FHIR Bundle - Required for FHIR Bundle conversion only**//
if (requestedPath == "/hl7v2/Bundle/" || requestedPath == "/hl7v2/Bundle") {
	//1.CIN
	checkRequiredHeader('X-TechBD-CIN', 'X-TechBD-CIN', true, 'patientCIN');

	//2.NPI
	var organizationNPI = $('headers').getHeader('X-TechBD-OrgNPI');

	//3.TIN
	var organizationTIN = $('headers').getHeader('X-TechBD-OrgTIN');

	// Check if both are missing — only then it's an error
	if ((organizationNPI == null || String(organizationNPI).trim() === "") &&
	    (organizationTIN == null || String(organizationTIN).trim() === "")) {
	    missingHeaders.push("Missing required header X-TechBD-OrgNPI and X-TechBD-OrgTIN. One is mandatory.");
	} else {
	    if (organizationNPI && String(organizationNPI).trim() !== "") {
	        channelMap.put('organizationNPI', organizationNPI);
	    }
	    if (organizationTIN && String(organizationTIN).trim() !== "") {
	        channelMap.put('organizationTIN', organizationTIN);
	    }
	}

	//4. Facility Code
	checkRequiredHeader('X-TechBD-Facility-ID', 'X-TechBD-Facility-ID', true, 'facilityID');

	//5. Encounter Type
	checkRequiredHeader('X-TechBD-Encounter-Type', 'X-TechBD-Encounter-Type', true, 'encounterType');

	//6. Part 2 Data Flagging 
	var part2DataFlag = $('headers').getHeader('X-TechBD-Part2');	
	if (part2DataFlag && String(part2DataFlag).trim() !== "") {
	    channelMap.put('X-TechBD-Part2', part2DataFlag);
	    channelMap.put('XTechBDPart2', part2DataFlag);
	}
	// 7. OMH Flagging
	var OMHFlag = $('headers').getHeader('X-TechBD-OMH');
	if (OMHFlag && String(OMHFlag).trim() !== "") {
	    channelMap.put('X-TechBD-OMH', OMHFlag);
	     channelMap.put('XTechBDOMH', OMHFlag);
	}

	// 8. OPWDD Flagging
	var OPWDDFlag = $('headers').getHeader('X-TechBD-OPWDD');
	if (OPWDDFlag && String(OPWDDFlag).trim() !== "") {
	    channelMap.put('X-TechBD-OPWDD', OPWDDFlag);
	    channelMap.put('XTechBDOPWDD', OPWDDFlag);
	}


	// Single consolidated log
    logger.info(
        logPrefix +
        "OrgNPI: " + organizationNPI +
        ", OrgTIN: " + organizationTIN +
        ", Part2: " + part2DataFlag +
        ", OMH: " + OMHFlag +
        ", OPWDD: " + OPWDDFlag
    );

}

// If any missing headers were found, throw a single error
if (missingHeaders.length > 0) {
    var errorMessage = "Bad Request: " + missingHeaders.join("; ");
    logger.error(logPrefix + errorMessage);
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}



//////////////////////////////////////////////////////
// Read environment variables and set to global map //
//////////////////////////////////////////////////////

// Initialize missing environment variables array
var missingEnvVars = [];

// Fetch and check environment variable: MC_FHIR_BUNDLE_SUBMISSION_API_URL
var fhirBundleSubmissionApiUrl = globalMap.get("fhirBundleSubmissionApiUrl");
if(fhirBundleSubmissionApiUrl != null) {
    globalMap.put('fhirBundleSubmissionApiUrl', fhirBundleSubmissionApiUrl);
} else {
    missingEnvVars.push("MC_FHIR_BUNDLE_SUBMISSION_API_URL is not set");
}

// If any env vars are missing, throw a single error
if (missingEnvVars.length > 0) {
    var errorMessage = "Server Error: " + missingEnvVars.join("; ");
    logger.error(errorMessage);
    setErrorResponse(500, errorMessage); // Internal Server Error
    throw errorMessage;
}

logger.info("HTTP request validation ended.");

//Check the file type, only .hl7 and .txt allowed
function getOutcome(text, severity, code, interactionId) {
    return JSON.stringify({
        resourceType: "OperationOutcome",
        interactionId : interactionId,
        result: [{
            severity: severity,
            code: code,
            details: { text: text }
        }]
    });
}
/**
* Util function to generate json string with status and message
*/
/*function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}*/

/**
* Util function to set error response.
* Replaced plain responseMap.put with a proper com.mirth.connect.userutil.Response object.
* When a throw occurs inside the source transformer, Mirth ignores plain responseMap string entries
* and returns a blank 200. By storing a Response(Status.SENT, body) into finalResponse (the channel
* responseVariable), Mirth honours our status code and body instead of emitting its auto-error fallback.
*/
/*function setErrorResponse(statusCode, errorMessage) {
    var body = createJsonResponse(statusCode, errorMessage);
    responseMap.put('status', String(statusCode));
    responseMap.put('message', errorMessage);
    var resp = new com.mirth.connect.userutil.Response(
        com.mirth.connect.userutil.Status.SENT,
        new java.lang.String(body)
    );
    responseMap.put('finalResponse', resp);
}*/


var interactionId = generateUuid();
globalMap.put('interactionId', interactionId);
var logPrefix = "[CHANNEL: " + channelName + "] [INTERACTION ID: " + interactionId + "] ";

var contentType = $('headers').getHeader('Content-Type');

if (!contentType) {
    var errorMessage = "Uploaded file is empty or missing.";
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}

if (!contentType || !contentType.toLowerCase().startsWith("multipart/form-data")) {
    var errorMessage = "Bad Request: Content-Type must be 'multipart/form-data' with boundary details.";
    setErrorResponse(400, errorMessage); 
    throw errorMessage;
}

var saveHL7Payload = globalMap.get('saveHL7Payload');

	var rawData = connectorMessage.getRawData();

		var partMatches = rawData.match(/Content-Disposition:/g) || [];
		var fileMatches = rawData.match(/filename="/g) || [];


		//Zero-file guard - catches the no-file-selected case where Postman sends a valid
		// multipart/form-data Content-Type with a boundary (so the boundary check above passes) but
		// all file rows are unchecked, leaving filename=" absent from the body. Without this check
		// the code falls through to the filename regex else-branch which calls setErrorResponse+throw
		// but Mirth ignores responseMap under a source-transformer throw and returns blank 200.
		// Catching it here explicitly with the fixed setErrorResponse (Response object) ensures 400.
		if (fileMatches.length === 0) {
		    var errorMessage = "Bad Request: No file is selected. Please attach a .hl7 or .txt file.";
		    logger.error(logPrefix + errorMessage);
		    setErrorResponse(400, errorMessage);
		    throw errorMessage;
		}

		// if more than one multipart input
		if (partMatches.length > 1) {
		    var errorMessage = "Invalid request. Only one file input is allowed.";
		    setErrorResponse(400, errorMessage);
		    throw errorMessage;
		}

		// if more than one file
		if (fileMatches.length > 1) {
		    var errorMessage = "Multiple files detected in upload. Only one file is allowed.";
		    setErrorResponse(400, errorMessage);
		    throw errorMessage;
		}

	if (!rawData || rawData.trim().length == 0 || rawData.trim() == '') {
	    errorMessage = "Uploaded file is empty or missing.";
	    setErrorResponse(400, errorMessage);
	    throw errorMessage;
	}

var filename = null;
var filenameMatch = rawData.match(/filename="([^"]+)"/);

if (filenameMatch && filenameMatch.length > 1) {
    filename = filenameMatch[1];
    globalMap.put('filename', filename);

    var extensionMatch = filename.match(/\.([0-9a-z]+)$/i);
    var extension = extensionMatch ? extensionMatch[1].toLowerCase().trim() : null;

    if (extension !== "hl7" && extension !== "txt") {
       var errorMessage = "Unsupported file extension: " + extension + ". Only .hl7 and .txt are allowed.";
       setErrorResponse(400, errorMessage); // Set the HTTP response status to 400 (Bad Request)
    	  throw errorMessage; // Stop further processing by throwing an exception
    }
} else {
    logger.warn(logPrefix + "Filename not found in message content.");
    errorMessage = "Uploaded file is empty or missing.";
    setErrorResponse(400, errorMessage);
    throw errorMessage;
}

var xml = new XML(rawData);
var hl7Message = xml.Content.Part.Content.toString();

// Parse request as XML
var requestXml = new XML(connectorMessage.getRawData());

// Extract HL7 body (the <Content> of the first <Part>)
var hl7Data = String(requestXml['Content']['Part']['Content']);

// Safety check
if (hl7Data == null || hl7Data.trim() === "") {
	logger.warn(logPrefix + "No HL7 content found in uploaded file.");
    var errorMessage = "Uploaded file is empty or missing.";
    	setErrorResponse(400, errorMessage);
    	throw errorMessage;
}


		try{
			//DB Save Original Payload
		     logger.info(logPrefix + "DB Save inside Source transformer");
		     var tenantId = $('headers').getHeader('X-TechBD-Tenant-ID');
		     channelMap.put('tenantId', tenantId);
		     var interactionId = globalMap.get('interactionId');
		     var operation = "saveOgHL7Payload";
		     var result = saveHL7Payload(
			   interactionId,
			   tenantId,
			   sourceMap.get('contextPath'),
			   hl7Message,
			   operation,
			   getHeaderValues()
			);
		} catch (e) {
			var errorMsg;
	            if (e instanceof JavaException) {
	                errorMsg = "HL7 Og Payload save: " + e.toString();
	                throw errorMessage;
	            } else {
	                errorMsg = "Unexpected error during saving: " + e.message;
	                throw errorMessage;
	            }
		}


// ---------------- HL7 VALIDATION ----------------

// Now validate HL7 lines
var lines = hl7Data.split(/\r?\n/);
if (!hl7Data.trim().startsWith("MSH|")) {
    var errorMessage = "Not a valid HL7 message. HL7 must start with 'MSH|'.";
    var outcome = getOutcome(errorMessage, "error", "invalid-msh", interactionId);
	try {
        var operation = "saveValidationFailed";
        saveHL7Payload(interactionId, tenantId, sourceMap.get('contextPath'), outcome, operation);
        logger.info(logPrefix + "Successfully saved validation failure information");
    } catch (saveError) {
        logger.error(logPrefix + "Failed to save validation failure: " + saveError.message);
    }
    responseMap.put('finalResponse', outcome);
    throw outcome;
}

for (var i = 0; i < lines.length; i++) {
    var line = lines[i].trim();
    if (line.startsWith("|")) {
        var errorMessage = "Not a valid HL7 data. Line " + (i + 1) + " starts with '|'.";
        var outcome = getOutcome(errorMessage, "error", "line-error", interactionId);
	try {
            var operation = "saveValidationFailed";
            saveHL7Payload(interactionId, tenantId, sourceMap.get('contextPath'), outcome, operation);
            logger.info(logPrefix + "Successfully saved validation failure information");
        } catch (saveError) {
            logger.error(logPrefix + "Failed to save validation failure: " + saveError.message);
        }
        responseMap.put('finalResponse', outcome);
    	 throw outcome;
    }
}



function getHeaderValues() {
	var headerJson = JSON.stringify({
        headers: {
            interactionId: channelMap.get('interactionId'),
            tenantName: channelMap.get('tenantId'),
            userAgent : channelMap.get('userAgent'),
            SeverityLevel : channelMap.get('SeverityLevel'), 
            uri : channelMap.get('uri'),
            contextPath : channelMap.get('contextPath'),
            CIN : channelMap.get('patientCIN'),
            NPI : channelMap.get('organizationNPI'),
            TIN : channelMap.get('organizationTIN'),
            FacilityID : channelMap.get('facilityID'),
            EncounterType : channelMap.get('encounterType'),
            Part2 : channelMap.get('X-TechBD-Part2'),
            OMH : channelMap.get('X-TechBD-OMH'),
            OPWDD : channelMap.get('X-TechBD-OPWDD'),
            BaseFHIRURL : channelMap.get('baseFhirUrl'),
            ValidationSeverityLevel : channelMap.get('SeverityLevel'),
            OrganizationName : channelMap.get('OrganizationName')
        }
    });
    return headerJson;
}

com.mirth.connect.plugins.javascriptrule.script:
var httpMethod = String(sourceMap.get('method')).toUpperCase();
var contextPath = String(connectorMessage.getSourceMap().get('contextPath')).replace(/\/$/, '');


/**
 * Util function to generate JSON string
 */
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

/**
 * Util function to set error response
 */
function setErrorResponse(statusCode, errorMessage) {
    responseMap.put('status', String(statusCode));
    responseMap.put('message', errorMessage);
    responseMap.put('finalResponse', createJsonResponse(statusCode, errorMessage));
}

/* =====================================
   1️⃣ ROOT ENDPOINT
===================================== */
if (contextPath === '') {

   if (httpMethod === 'GET') {

    responseMap.put('responseStatusCode', 200);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify({
        status: 200,
        message: "OK"
    }));

   return false;
}

    // Method not allowed for /
    return methodNotAllowed();
}

/* =====================================
   2️⃣ HEALTHCHECK

===================================== */
if (contextPath === '/healthcheck') {

    if (httpMethod === 'GET') {
         responseMap.put('responseStatusCode', 200);
	    responseMap.put('responseContentType', 'application/json');
	    responseMap.put('responseBody', JSON.stringify({
	        status: 200,
	        message: "OK"
	    }));

	   return false;
    }

    return methodNotAllowed();
}

/* =====================================
   3️ BUNDLE
===================================== */
if (contextPath === '/hl7v2/Bundle/$validate' || contextPath === '/hl7v2/Bundle/$validate/'
|| contextPath === '/hl7v2/Bundle' || contextPath === '/hl7v2/Bundle/') {

    if (httpMethod === 'POST' || httpMethod === 'OPTIONS') {
        return true;
    }

    return methodNotAllowed();
}

/* =====================================
   ❌ INVALID PATH → 404
===================================== */
return notFound();




/* =====================================
   Helper Functions
===================================== */

function methodNotAllowed() {

    var errorResponse = "Method Not Allowed.";

    responseMap.put('responseStatusCode', 405);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(405, errorResponse);

    throw "Invalid method";
}

function notFound() {

    var errorResponse = "Not Found: Invalid endpoint.";

    responseMap.put('responseStatusCode', 404);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(404, errorResponse);

    throw "Invalid endpoint";
}

com.mirth.connect.plugins.javascriptstep.script:
// --------------------
// Helper: Get JSON Outcome
// --------------------
function getOutcome(text, severity, code, interactionId) {
    return JSON.stringify({
        resourceType: "OperationOutcome",
        interactionId : interactionId,
        result: [{
            severity: severity,
            code: code,
            details: { text: text }
        }]
    });
}
var interactionId = globalMap.get('interactionId');
var logPrefix = "[CHANNEL: " + channelName + "] [INTERACTION ID: " + interactionId + "] ";
// --------------------
// Helper: Extract HL7 body from raw data
// --------------------
function extractHL7Body(rawData) {
    var match = rawData.match(/MSH\|[\s\S]*/);
    return match ? match[0].trim() : "";
}

// --------------------
// Helper: Extract segments from HL7 input
// --------------------
function extractSegments(hl7Text) {
    var lines = hl7Text.split(/\r\n|\n|\r/);
    var segments = [];

    for (var i = 0; i < lines.length; i++) {
        var line = lines[i].trim();
        if (line && line.includes('|')) {
            var seg = String(line.split('|')[0].trim()); // Force to JS string
            if (/^[A-Z0-9]{2,5}$/.test(seg)) {
                segments.push(seg);
            }
        }
    }

    return segments;
}

function validateFieldsInAllSegments(segmentName, fieldIndex, componentIndex, hl7Text, fieldName, description) {
    var lines = hl7Text.split(/\r\n|\n|\r/);
    var violations = [];

    for (var i = 0; i < lines.length; i++) {
        var line = lines[i];

        if (line.startsWith(segmentName + "|")) {
            var fields = line.split("|");

            // Pad fields if necessary
            while (fields.length < fieldIndex) {
                fields.push("");
            }

            var value = fields[fieldIndex] || "";

            if (componentIndex != null) {
                var components = value.split("^");
                value = components.length >= componentIndex ? components[componentIndex - 1].trim() : "";
            } else {
                value = value.trim();
            }

            if (!value) {
                violations.push({
                    lineNumber: i + 1,
                    segment: segmentName,
                    fieldIndex: fieldIndex,
                    fieldName: fieldName,
                    description: description,
                    lineContent: line
                });
            }
        }
    }

    return violations;
}

function getRequiredSegmentsAndFieldsFromXml(xmlInput) {


		var SAXBuilder = Packages.org.jdom2.input.SAXBuilder;
		    var StringReader = java.io.StringReader;
		    var InputSource = org.xml.sax.InputSource;
		    var builder = new SAXBuilder();
		    var document;

		    // Detect whether the input is XML text or a file path
		    if (xmlInput && xmlInput.trim().startsWith("<")) {
		        logger.info("Parsing validation XML from in-memory string...");
		        var inputSource = new InputSource(new StringReader(xmlInput));
		        document = builder.build(inputSource);
		    } else {
		        logger.info("Parsing validation XML from file path...");
		        var File = java.io.File;
		        var file = new File(xmlInput);
		        if (!file.exists()) throw new Error("Template XML file not found: " + xmlInput);
		        document = builder.build(file);
		    }

    var root = document.getRootElement();

    var messageStructure = root.getChild("MessageStructure");
    var segmentGroup = messageStructure.getChild("SegmentGroup");
    var segmentElems = segmentGroup.getChildren("Segment");

    var requiredSegments = [];
    for each (var seg in segmentElems) {
        var usage = seg.getAttributeValue("Usage");
        var name = seg.getAttributeValue("Name");
        if ("R".equalsIgnoreCase(usage) && name) {
            requiredSegments.push(name);
        }
    }

    var segmentsSection = root.getChild("Segments");
    var segmentDefs = segmentsSection.getChildren("SegmentDef");

    var requiredFields = [];
    var oneOfGroups = [];

    for each (var segDef in segmentDefs) {
        var segmentName = segDef.getAttributeValue("Name");
        var fields = segDef.getChildren("Field");

        for each (var field in fields) {
		    var usage = field.getAttributeValue("Usage");
		    var fieldName = field.getAttributeValue("Name");
		    fieldName = String(fieldName).trim();
			var description = String(field.getAttributeValue("Description") || "").trim();

		    if (!fieldName) {
		        logger.warn(logPrefix + "Skipping field: Missing field name entirely");
		        continue;
		    }

		    fieldName = String(fieldName).trim();

		    if (!"R".equalsIgnoreCase(usage)) {
		        logger.info(logPrefix + "Skipping non-required field: " + fieldName + " (Usage=" + usage + ")");
		        continue;
		    }

		    if (!fieldName.match(/^[A-Z0-9]{3,5}-\d+(\.\d+)?$/)) {
		        logger.warn(logPrefix + "Field does not match pattern: '" + fieldName + "' (Length=" + fieldName.length + ")");
		        continue;
		    }

		    var fieldParts = fieldName.split("-");
		    if (fieldParts.length !== 2) {
		        logger.warn(logPrefix + "Unexpected field format: '" + fieldName + "', parts=" + fieldParts);
		        continue;
		    }

		    var seg = fieldParts[0];
		    var fieldComp = fieldParts[1].split(".");

		    var fieldIndex = parseInt(fieldComp[0], 10);
		    if (isNaN(fieldIndex)) {
		        logger.warn(logPrefix + "Could not parse fieldIndex: '" + fieldComp[0] + "' from fieldName: '" + fieldName + "'");
		        continue;
		    }

		    var componentIndex = null;
		    if (fieldComp.length > 1) {
		        componentIndex = parseInt(fieldComp[1], 10);
		        if (isNaN(componentIndex)) {
		            logger.warn(logPrefix + "Could not parse componentIndex: '" + fieldComp[1] + "' from fieldName: '" + fieldName + "'");
		            continue;
		        }
		    }

		    requiredFields.push({
		        segment: seg,
		        fieldIndex: fieldIndex,
		        componentIndex: componentIndex,
		        fieldName: fieldName,
		        description: description
		    });

		    logger.info(logPrefix + "✅ Extracted required field: " + seg + "-" + fieldIndex + (componentIndex ? "." + componentIndex : ""));
		}

		// Handle <OneOfGroup>
        var groups = segDef.getChildren("OneOfGroup");
        for each (var group in groups) {
            var groupFields = [];
            var groupDesc = group.getAttributeValue("Description") || "";

            for each (var field in group.getChildren("Field")) {
                var fieldName = String(field.getAttributeValue("Name")).trim();
                var description = String(field.getAttributeValue("Description") || "").trim();

                var parts = fieldName.split("-");
                var seg = parts[0];
                var idxComp = parts[1].split(".");
                var fieldIndex = parseInt(idxComp[0], 10);
                var componentIndex = idxComp.length > 1 ? parseInt(idxComp[1], 10) : null;

                groupFields.push({
                    segment: seg,
                    fieldIndex: fieldIndex,
                    componentIndex: componentIndex,
                    fieldName: fieldName,
                    description: description
                });
            }

            oneOfGroups.push({
                segment: segmentName,
                description: groupDesc,
                fields: groupFields
            });
        }
    }


    return {
        requiredSegments: requiredSegments,
        requiredFields: requiredFields,
        oneOfGroups: oneOfGroups
    };
}

function validateOneOfGroups(groups, hl7Text) {
    var violations = [];

    var lines = hl7Text.split(/\r\n|\n|\r/);

    for each (var group in groups) {
        var satisfied = false;

        for each (var f in group.fields) {
            var fieldViolations = validateFieldsInAllSegments(
                f.segment, f.fieldIndex, f.componentIndex, hl7Text,
                f.fieldName, f.description
            );
            if (fieldViolations.length === 0) {
                satisfied = true;
                break;
            }
        }

        if (!satisfied) {
            violations.push({
                segment: group.segment,
                fieldName: group.fields.map(f => f.fieldName).join(" OR "),
                description: group.description,
                lineNumber: "-", // optional: could inspect the first PID line
                lineContent: ""  // optional
            });
        }
    }
    return violations;
}


function validateOBXSpecialRule(hl7Text) {

    var violations = [];
    var lines = hl7Text.split(/\r\n|\n|\r/);

    for (var i = 0; i < lines.length; i++) {
        var line = lines[i];
        if (line.startsWith("OBX|")) {
            var fields = line.split("|");
            // Ensure OBX-3 exists
            if (fields.length < 4) {
                violations.push({
                    lineNumber: i + 1,
                    segment: "OBX",
                    fieldName: "OBX-3.1",
                    description: "OBX-3 missing entirely",
                    lineContent: line
                });
                continue;
            }

            var obx3 = fields[3] || "";
            var components = obx3.split("^");

            var obx3_1 = components.length >= 1 ? components[0].trim() : "";
            var obx3_2 = components.length >= 2 ? components[1].trim().toLowerCase() : "";


            // Skip rule ONLY if OBX-3.2 matches special phrase
            if (obx3_2 === "ahc-hrsn patient consent") {
                continue;
            }

            // Otherwise OBX-3.1 must exist
            if (!obx3_1) {
                violations.push({
                    lineNumber: i + 1,
                    segment: "OBX",
                    fieldName: "OBX-3.1",
                    description: "OBX-3.1 required unless OBX-3.2 is 'ahc-hrsn patient consent'",
                    lineContent: line
                });
            }
        }
    }
    return violations;
}

function validateOrganizationName(hl7Text) {
    var violations = [];

    // Check header first
    var orgNameHeader = channelMap.get("OrganizationName");
     if (orgNameHeader && String(orgNameHeader).trim().length > 0) {

        return violations;
    }

    // Check MSH-6
    var lines = hl7Text.split(/\r\n|\n|\r/);
    for (var i = 0; i < lines.length; i++) {
        var line = lines[i];
        if (line.startsWith("MSH|")) {
            var fields = line.split("|");
            if (fields.length >= 6) {
                var msh6 = fields[5] ? fields[5].trim() : "";
                if (msh6.length > 0) {  
                    return violations;
                }
            }
            break;
        }
    }

    // If both empty → error
    violations.push({
        segment: "MSH",
        fieldName: "Organization Name",
        description: "Organization Name must be provided either in header 'X-TechBD-Organization-Name' or in MSH-6",
        lineNumber: "-",
        lineContent: ""
    });
    return violations;
}

/**
* Replacer function to remove empty values
*/function removeEmptyValues(key, value) {  // Remove values that are empty strings, null, undefined, or empty objects/arrays  if (value === "" || value === null || value === undefined ||       (typeof value === "object" && Object.keys(value).length === 0) ||      (Array.isArray(value) && value.length === 0)) {    return undefined; // Exclude the key from the result  }  return value; // Keep the value as is}
