function getConsentResourceStatus(sourceXml) {
	try {
		var consentInfo = {};
	    	consentInfo.code = 'Consent-Status';
	    	consentInfo.status = "TechBD-Generated";
		var xmlDoc = new XML(sourceXml); // Convert XML string to XML object			
		//default xml namespace = "urn:hl7-org:v3"; // Default namespace for HL7 documents
		var consentCode = "";
		for each (var obx in xmlDoc..OBX) {
		    var obx32 = "";
		    //////////////////////////////////////////
		    if (obx["OBX.3"] != null && obx["OBX.3"]["OBX.3.1"] != null) {
		        obx31 = obx["OBX.3"]["OBX.3.1"].toString();
		    }
		    /////////////////////////////////////////
		    if (obx["OBX.3"] != null && obx["OBX.3"]["OBX.3.2"] != null) {
		        obx32 = obx["OBX.3"]["OBX.3.2"].toString();
		    }

		    if (obx31 == "105511-0" || obx32 == "AHC-HRSN Patient Consent") {
		        if (obx["OBX.5"] != null && obx["OBX.5"]["OBX.5.2"] != null) {
		            consentCode = obx["OBX.5"]["OBX.5.2"].toString();
		        }
		        break;
		    }
		}
		logger.info(logPrefix + "Consent Code: " + consentCode);
		if (consentCode != undefined && consentCode.length > 0) {
		    logger.info(logPrefix + "Consent Code: " + consentCode);
		        consentInfo.status = "provided";
		}		
		// Convert to JSON string (optional, for sending/logging)
		var consentJsonString = JSON.stringify(consentInfo);
		channelMap.put('elaboration', consentJsonString);
	} catch (e) {
        var errorMsg;
        if (e instanceof JavaException) {
           errorMsg = "Error parsing Consent Resource: " + e.toString();
        } else {
           errorMsg = "Unexpected error during getting Consent Resource: " + e.message;
        }
        logger.error(logPrefix + errorMsg);

        // Failure: Return an OperationOutcome JSON response with validation errors
        responseMap.put('finalResponse', JSON.stringify(getJsonInvalidOperationOutcome(errorMsg, "invalid")));

        throw new Error(errorMsg);
     }
}

function getCategoryDisplay(code) {
    switch (code) {
        case '71802-3':
            return 'Housing Instability';
        case '96778-6':
            return 'Inadequate Housing';
        case '96779-4':
            return 'Utility Insecurity';
        case '88122-7':
        case '88123-5':
            return 'Food Insecurity';
        case '93030-5':
            return 'Transportation Insecurity';
        case '96780-2':
            return 'Employment Status';
        case '96782-8':
        case '95618-5':
        case '95617-7':
        case '95616-9':
        case '95615-1':
        case '95614-4':
            return 'SDOH Category Unspecified';
        default:
            return 'SDOH Category Unspecified';
    }
}

function getCategoryCode(code) {
    switch (code) {
        case '71802-3':
            return 'housing-instability';
        case '96778-6':
            return 'inadequate-housing';
        case '96779-4':
            return 'utility-insecurity';
        case '88122-7':
        case '88123-5':
            return 'food-insecurity';
        case '93030-5':
            return 'transportation-insecurity';
        case '96780-2':
            return 'employment-status';
        case '96782-8':
        case '95618-5':
        case '95617-7':
        case '95616-9':
        case '95615-1':
        case '95614-4':
            return 'sdoh-category-unspecified';
        default:
            return null;
    }
}

// Define Namespace Resolver
function getObservationCategoryCodes(transformer, observations) {    
    var xml = new XML(observations);  

    var categorySystem = "http://hl7.org/fhir/us/sdoh-clinicalcare/CodeSystem/SDOHCC-CodeSystemTemporaryCodes";

	var categorySet = {};

	var children = xml.children();
    var currentOBR = null;

    for each (var child in children) {
	    var nodeName = child.name().localName;

	    if (nodeName === 'OBR') {
	        currentOBR = child;
	    } else if (nodeName === 'OBX' && currentOBR != null) {
	        var questionCode = "";
	        var displayCode = "";

	        if (child["OBX.3"] != null) {
	            if (child["OBX.3"]["OBX.3.1"] != null) {
	                questionCode = child["OBX.3"]["OBX.3.1"].toString().trim();
	            }
	            if (child["OBX.3"]["OBX.3.2"] != null) {
	                displayCode = child["OBX.3"]["OBX.3.2"].toString().trim();
	            }
	        }

	        // Filter like in XSLT logic
	        if (questionCode === '' || questionCode === '105511-0' || displayCode === 'AHC-HRSN Patient Consent') {
	            continue;
	        }

	        var categoryCode = getCategoryCode(questionCode);
	        var categoryDisplay = getCategoryDisplay(questionCode);

	        if (categoryCode && !(categoryCode in categorySet)) {
	            categorySet[categoryCode] = categoryDisplay;
	        }
	    }
	}

    // Build the category JSON array
    var categoryJsonArray = [];
    for (var code in categorySet) {
        categoryJsonArray.push({
            system: categorySystem,
            code: code,
            display: categorySet[code]
        });
    }

     var categoryXml = JSON.stringify(categoryJsonArray);

	transformer.setParameter('categoryXml', categoryXml);
	logger.info(logPrefix + "categoryXml : " + categoryXml);
	return transformer;
}

function generateSHA256(inputString) {
    //var md = MessageDigest.getInstance("SHA-256");
    var md = Packages.java.security.MessageDigest.getInstance("SHA-256");
    md.update(inputString.getBytes("UTF-8"));   
    var digest = md.digest();
    return bytesToHex(digest);
}

function bytesToHex(byteArray) {
    var hexString = new java.lang.StringBuilder();
    for (var i = 0; i < byteArray.length; i++) {
        var hex = java.lang.Integer.toHexString(0xff & byteArray[i]);
        if (hex.length == 1) hexString.append('0');
        hexString.append(hex);
    }
    return hexString.toString();
}

function generateSHA256Id(sourceXml, resourceName, resourceIdName, transformer, additionalString) {
    if (sourceXml != undefined) { 
    	var xmlDoc = new XML(sourceXml);
        // Get MRN and CIN from channelMap
        var mrn = channelMap.get('patientMRN') || "";
        var cin = channelMap.get('patientCIN') || "";
        var combinedText = mrn + cin;

        if (typeof additionalString !== 'undefined' && additionalString != null && additionalString !== '') {
            combinedText += additionalString;
        }

        var resourceText = resourceName + xmlDoc.toString().trim();
        combinedText += resourceText;

        // Generate SHA-256 hash
        var sha256Hash = generateSHA256(new java.lang.String(combinedText));
        transformer.setParameter(resourceIdName, sha256Hash);
        channelMap.put(resourceName + "_Resource_ID", sha256Hash);
        logger.info(resourceName + " Resource_ID : " + sha256Hash);
    } else {
        logger.error(resourceName + " not found in the XML.");
    }

    return transformer;
}

function generateCompactSha256(sourceXml, resourceName, resourceIdName, transformer) {
    if (sourceXml != undefined) { 
	    var MessageDigest = Packages.java.security.MessageDigest;
	    var digest = MessageDigest.getInstance("SHA-256");

	    // Raw SHA-256 bytes
	    var hashBytes = digest.digest(new java.lang.String(sourceXml).getBytes("UTF-8"));

	    // Base64 URL-safe encoding
	    var sha256Hash = Packages.java.util.Base64
	        .getUrlEncoder()
	        .withoutPadding()
	        .encodeToString(hashBytes);

	    // Convert Java String to JavaScript String
	    sha256Hash = String(sha256Hash).replace(/_/g, '-');

	    transformer.setParameter(resourceIdName, sha256Hash);
	    channelMap.put(resourceName + "_Resource_ID", sha256Hash);
	    logger.info(resourceName + " Resource_ID : " + sha256Hash);
    } else {
	        logger.error(resourceName + " not found.");
	    }

    return transformer;
}

