function getMultipleAnswersForComponent(transformer, observations) {
    var xml = new XML(observations);
    var codingArray = [];
    var seenCodes = {};

    var obxList = xml..OBX;

    for each (var obx in obxList) {
        var obxCode = obx['OBX.3']['OBX.3.1'].toString().trim();

        if (obxCode === '96778-6') {
            var values = obx['OBX.5'];

            for each (var val in values) {
                var code = val['OBX.5.1'].toString().trim();
                var display = val['OBX.5.2'].toString().trim();

                if (code && !seenCodes[code]) {
                    codingArray.push({
                        "system": "http://loinc.org",
                        "code": code,
                        "display": display
                    });
                    seenCodes[code] = true;
                }
            }
        }
    }

    transformer.setParameter('componentAnswersXml', JSON.stringify(codingArray));
    return transformer;
}

