	for (var i = 0; i < segments.length(); i++) {	
	    var segment = segments[i];

	    // Process only OBR
	    if (segment.name() == "OBR") {	
	        var obr26 = "";	
	        if (segment["OBR.26"] && segment["OBR.26"]["OBR.26.1"]) {
	            obr26 = segment["OBR.26"]["OBR.26.1"].toString().trim();
	        }

	        // Extract screening code
	        var screeningCode = "";	
	        if (obr26.indexOf("&") >= 0) {
	            screeningCode = obr26.split("&")[0].trim();
	        } else {
	            screeningCode = obr26;
	        }

