		        	  var operation = "saveValidationFailed";
		            saveHL7Payload(interactionId, tenantId, requestedPath, getOutcome(errorMsg, "error", "unexpected-error", interactionId), operation);
		            logger.info(logPrefix + "Successfully saved validation failure information");
		        } catch (saveError) {
		            logger.error(logPrefix + "Failed to save validation failure: " + saveError.message);
		        }
			        		    logger.error(logPrefix + "Error during HL7 FHIR bundle transformation: " + e);		    throw e;		}

		// Convert the XML document to JSON
		const jsonResult = cleanedJsonString;
		channelMap.put('jsonResult', jsonResult);
		responseMap.put('finalResponse', JSON.stringify(jsonResult));



    channelMap.put('xslt_result', cleanedJsonString);
    return cleanedJsonString;

} catch (e) {
    var errorMsg = "Error during XSLT transformation: " + e.message + "\nDetails: " + e;
    logger.error(logPrefix + errorMsg);

	try {
		 var operation = "saveValidationFailed";
		 saveHL7Payload(interactionId, tenantId, requestedPath, getOutcome(errorMsg, "error", "unexpected-error", interactionId), operation);
		  logger.info(logPrefix + "Successfully saved validation failure information");
		} catch (saveError) {
		    logger.error(logPrefix + "Failed to save validation failure: " + saveError.message);
		}

    channelMap.put('xslt_result', errorMsg);
    throw e;
}
}

function removeEmptyValues(key, value) {   
// Remove values that are empty strings, null, undefined, or empty objects/arrays   
if (value === "" || value === null || value === undefined ||       
(typeof value === "object" && Object.keys(value).length === 0) ||       
(Array.isArray(value) && value.length === 0)) {     
return undefined;  
}   
return value;
}

channel.preprocessingScript:
var requestedPath = sourceMap.get('contextPath');

if (requestedPath == "/") {
	return;
}

var index = message.indexOf("MSH|");
if (index !== -1) {
    message = message.substring(0, index) + "\r\n" + message.substring(index);
}

var rawData = connectorMessage.getRawData();
// Extract filename from multipart request
var filenameMatch = rawData.match(/filename="([^"]+)"/);
if (filenameMatch && filenameMatch.length > 1) {

    var filename = filenameMatch[1];

    // Extract extension
    var extensionMatch = filename.match(/\.([0-9a-z]+)$/i);
    var extension = extensionMatch ? extensionMatch[1].toLowerCase() : "";

    // Reject ZIP uploads
    if (extension === "zip") {

        var errorMessage = "Unsupported file extension: " + extension + ". Only .hl7 and .txt are allowed.";
        responseMap.put("status", "400");
        responseMap.put("message", errorMessage);
        responseMap.put(
            "finalResponse",
            JSON.stringify({ status: 400, message: errorMessage })
        );

        throw errorMessage;
    }
}
