/****************************************************************************************
 //** CHANGES MADE FOR IMPLEMENTING LOOKUP MANAGER CONFIG:
 //** JDBC URL is fetched as a plain-text Lookup Manager configuration
 //** JDBC Username & Password are fetched from Lookup Manager configuration
 //** Replaced System.getenv() based configuration
****************************************************************************************/

try {


    /*************** JDBC URL (PLAIN TEXT) ****************/

    var jdbcUrl = LookupHelper.get("Config-sensitive", "MC_JDBC_URL");

    if (!jdbcUrl) {
        throw "Empty JDBC URL returned from Lookup Manager (Config-sensitive group)";
    }

// Step 2: Get ACTUAL USERNAME directly from Lookup Manager
    var jdbcUsername = LookupHelper.get("Config-sensitive", "MC_JDBC_USERNAME");

    if (!jdbcUsername || jdbcUsername.trim() === "") {
        throw "MC_JDBC_USERNAME not configured in Lookup Manager (Config-sensitive group)";
    }

    jdbcUsername = jdbcUsername.trim();

    // Step 3: Get ACTUAL PASSWORD directly from Lookup Manager
    var jdbcPassword = LookupHelper.get("Config-sensitive", "MC_JDBC_PASSWORD");

    if (!jdbcPassword || jdbcPassword.trim() === "") {
        throw "MC_JDBC_PASSWORD not configured in Lookup Manager (Config-sensitive group)";
    }

    jdbcPassword = jdbcPassword.trim();

   /*************** STORE VALUES ****************/

    globalMap.put("jdbcUrl", jdbcUrl);
    globalMap.put("jdbcUsername", jdbcUsername);
    globalMap.put("jdbcPassword", jdbcPassword);

} catch (e) {
    logger.error("❌ HL7 JDBC initialization failed during channel deploy: " + e);
    throw e; // Fail channel deployment
}

/********************************************
    3️⃣ FETCH FHIR BUNDLE SUBMISSION API URL (Plain text)
********************************************/
try {
    var fhirApiUrl = LookupHelper.get("Config", "MC_FHIR_BUNDLE_SUBMISSION_API_URL");

    fhirApiUrl = fhirApiUrl.trim(); 
    if (!fhirApiUrl || fhirApiUrl.trim() === "") {
        throw "Lookup Manager configuration for FHIR API URL returned an empty value.";
    }

    //channelMap.put("FHIR_API_URL", fhirApiUrl);
    globalMap.put("fhirBundleSubmissionApiUrl", fhirApiUrl);

} catch (e) {
    logger.error("❌ Error fetching FHIR API URL: " + e);
    setErrorResponse(500, "Failed to load FHIR API URL");
    throw e;
}

/////////////
/********************************************
    2️⃣ FETCH DATA LEDGER API KEY (Plain text)
********************************************/

try {
    var dataLedgerKey = LookupHelper.get("Config-sensitive", "TECHBD_NYEC_DATALEDGER_API_KEY");

    globalMap.put("DATA_LEDGER_API_KEY", dataLedgerKey);

} catch (e) {
    logger.error("❌ Error processing DataLedger API Key from Lookup Manager (Config-sensitive group): " + e.message);
}

/////////////
/********************************************
    8️⃣ FETCH DATA LEDGER API URL (Plain text)
********************************************/

try {
    var ledgerUrl = LookupHelper.get("Config", "DATA_LEDGER_API_URL");

     globalMap.put("DATA_LEDGER_API_URL", ledgerUrl);

} catch (e) {
    logger.error("❌ Error processing DataLedger API URL from Lookup Manager (Config-sensitive group): " + e.message);
}
////////////////
try {

    // DATA_LEDGER_TRACKING (true / false)
    var trackingEnabled = LookupHelper.get("Config", "DATA_LEDGER_TRACKING");
    if (!trackingEnabled || trackingEnabled.trim() === "") {
        throw "DATA_LEDGER_TRACKING is not configured in Lookup Manager";
    }
    globalMap.put("DATA_LEDGER_TRACKING", trackingEnabled.trim());

    // MC_VALID_FHIR_URLS (comma-separated list)
    var validUrlsEnv = LookupHelper.get("Config", "MC_VALID_FHIR_URLS");
    if (!validUrlsEnv || validUrlsEnv.trim() === "") {
        throw "MC_VALID_FHIR_URLS is not configured in Lookup Manager";
    }
    globalMap.put("MC_VALID_FHIR_URLS", validUrlsEnv.trim());

    logger.info("✔ Tracking flag and valid FHIR URLs loaded from Lookup Manager");

} catch (e) {
    logger.error("❌ Failed to load tracking / valid URLs config: " + e);
    throw e;
}



/********************************************
    7️⃣ FETCH HUB UI URL (Plain text)
********************************************/
// Retrieves the Hub UI URL used to populate the Access-Control-Allow-Origin header.
try {
    var hubUiUrl = LookupHelper.get("Config", "HUB_UI_URL");

    if (!hubUiUrl || hubUiUrl.trim() === "") {
        throw "Lookup Manager configuration for HUB_UI_URL returned empty.";
    }

    hubUiUrl = hubUiUrl.trim();

   globalMap.put("HUB_UI_URL", hubUiUrl);

    logger.info("✔ HUB UI URL loaded from Lookup Manager configuration: ");

} catch (e) {
    logger.error("❌ Error fetching HUB UI URL: " + e);
    setErrorResponse(500, "Failed to load HUB UI URL");
    throw e;
}
////////////////////////////////////////////////////
return message;

channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map

// Version: 0.4.3 - Added support for X-TechBD-Base-FHIR-URL
// Version: 0.4.15 - Added filters to source and bundle destination and changed the globalMap usage to channelMap

var endpoint = channelMap.get("endpoint");
if(endpoint == 'bundle') {
	// Get the response from the HTTP Writer destination
	var destinationName = "dest_bundle";
	var destinationResponse = responseMap.get(destinationName);

	// Check if the response exists
	if (destinationResponse) {
	    var responseStatus = destinationResponse.getStatus();  // HTTP status code
	    var responseData = destinationResponse.getMessage();   // Response message body
		responseMap.put('finalResponse', responseData);

	    // Log the response details
	    logger.info("Response from " + destinationName + ":"+" Status Code: " + responseStatus+"Response Data: " + responseData);

	} else {
	    logger.info("No response found for destination: " + destinationName);
	}
}
return;

